import React, { useEffect, useRef } from 'react';
import { GoabCallout } from '@abgov/react-components';

interface ValidationError {
  field: string;
  message: string;
}

interface ValidationErrorSummaryProps {
  errors: ValidationError[];
  headingText?: string;
}

export function ValidationErrorSummary({
  errors,
  headingText = 'There is a problem'
}: ValidationErrorSummaryProps) {
  const summaryRef = useRef<HTMLDivElement>(null);

  // Focus error summary when it appears
  useEffect(() => {
    if (errors.length > 0 && summaryRef.current) {
      summaryRef.current.focus();
    }
  }, [errors]);

  if (errors.length === 0) {
    return null;
  }

  const handleErrorClick = (e: React.MouseEvent<HTMLAnchorElement>, field: string) => {
    e.preventDefault();
    const element = document.querySelector(`[name="${field}"]`) as HTMLElement;
    if (element) {
      element.focus();
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  };

  return (
    <div
      ref={summaryRef}
      className="error-summary"
      role="alert"
      aria-labelledby="error-summary-heading"
      tabIndex={-1}
    >
      <h2 id="error-summary-heading" className="error-summary__heading">
        {headingText}
      </h2>
      <ul className="error-summary__list">
        {errors.map((error) => (
          <li key={error.field}>
            <a
              href={`#${error.field}`}
              onClick={(e) => handleErrorClick(e, error.field)}
            >
              {error.message}
            </a>
          </li>
        ))}
      </ul>
    </div>
  );
}

// Alternative using GoabCallout component:
export function ValidationErrorCallout({
  errors,
  headingText = 'There is a problem'
}: ValidationErrorSummaryProps) {
  if (errors.length === 0) {
    return null;
  }

  const handleErrorClick = (e: React.MouseEvent<HTMLAnchorElement>, field: string) => {
    e.preventDefault();
    const element = document.querySelector(`[name="${field}"]`) as HTMLElement;
    if (element) {
      element.focus();
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  };

  return (
    <GoabCallout type="emergency" heading={headingText} mb="xl">
      <ul className="error-summary__list" style={{ margin: 0, paddingLeft: 'var(--goa-space-l)' }}>
        {errors.map((error) => (
          <li key={error.field} style={{ marginBottom: 'var(--goa-space-xs)' }}>
            <a
              href={`#${error.field}`}
              onClick={(e) => handleErrorClick(e, error.field)}
              style={{ color: 'inherit', textDecoration: 'underline' }}
            >
              {error.message}
            </a>
          </li>
        ))}
      </ul>
    </GoabCallout>
  );
}

// Example usage in a form step:
function ExampleFormStep() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [errors, setErrors] = useState<ValidationError[]>([]);

  const validateForm = (): boolean => {
    const newErrors: ValidationError[] = [];

    if (!name.trim()) {
      newErrors.push({
        field: 'fullName',
        message: 'Enter your full name'
      });
    }

    if (!email.trim()) {
      newErrors.push({
        field: 'email',
        message: 'Enter your email address'
      });
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      newErrors.push({
        field: 'email',
        message: 'Enter a valid email address'
      });
    }

    setErrors(newErrors);
    return newErrors.length === 0;
  };

  const handleContinue = () => {
    if (validateForm()) {
      // Proceed to next step
      console.log('Form valid, continuing...');
    }
  };

  return (
    <div className="form-page">
      <ValidationErrorSummary errors={errors} />

      <h1 className="step-title">Personal Information</h1>

      <form className="question-group">
        <GoabFormItem
          label="What is your full name?"
          error={errors.find(e => e.field === 'fullName')?.message}
          requirement="required"
        >
          <GoabInput
            name="fullName"
            id="fullName"
            value={name}
            onChange={(e) => setName(e.value)}
            error={!!errors.find(e => e.field === 'fullName')}
          />
        </GoabFormItem>

        <GoabFormItem
          label="What is your email address?"
          error={errors.find(e => e.field === 'email')?.message}
          requirement="required"
        >
          <GoabInput
            name="email"
            id="email"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.value)}
            error={!!errors.find(e => e.field === 'email')}
          />
        </GoabFormItem>

        <div className="form-actions">
          <GoabButton type="primary" onClick={handleContinue}>
            Save and continue
          </GoabButton>
        </div>
      </form>
    </div>
  );
}

